#include <stdio.h>
#include <limits.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        int a;
        int maxVal = INT_MIN;
        int arr[200000]; // sum of N fits in memory
        for (int i = 0; i < N; ++i) {
            scanf("%d", &a);
            arr[i] = a;
            if (a > maxVal) maxVal = a;
        }
        long long ans = 0;
        for (int i = 0; i < N; ++i) {
            if (arr[i] == maxVal) {
                int pos = i + 1; // 1‑based
                if (pos >= K) ans += (long long)(N - i);
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

